399	              `STOP and diagnose: what assumption is wrong? Try a different approach.`
400	            );
401	          }
402	          session.onUpdate?.(session);
403	        }
404	        break;
405	      }
406	      default:
407	        // Ignore plan/user_message_chunk/etc. for the bridge.
408	        break;
409	    }
